const https = require('https');
const http = require('http');
const { URL } = require('url');

const ALLOWED_PROTOCOLS = ['http:', 'https:'];
const BLOCKED_IP_RANGES = [
  /^127\./,
  /^10\./,
  /^172\.(1[6-9]|2[0-9]|3[0-1])\./,
  /^192\.168\./,
  /^169\.254\./,
  /^::1$/,
  /^fc00:/,
  /^fe80:/,
  /^::ffff:127\./,
  /^::ffff:10\./,
  /^::ffff:172\.(1[6-9]|2[0-9]|3[0-1])\./,
  /^::ffff:192\.168\./,
  /^localhost$/i
];

const TIMEOUT = 10000;
const MAX_REDIRECTS = 5;
const MAX_RESPONSE_SIZE = 5 * 1024 * 1024;

function isPrivateIP(hostname) {
  for (const pattern of BLOCKED_IP_RANGES) {
    if (pattern.test(hostname)) {
      return true;
    }
  }
  return false;
}

function validateURL(urlString) {
  let parsedUrl;
  try {
    parsedUrl = new URL(urlString);
  } catch (error) {
    throw new Error('Invalid URL format');
  }

  if (!ALLOWED_PROTOCOLS.includes(parsedUrl.protocol)) {
    throw new Error('Protocol not allowed. Only HTTP and HTTPS are supported');
  }

  if (!parsedUrl.hostname) {
    throw new Error('Invalid hostname');
  }

  if (isPrivateIP(parsedUrl.hostname)) {
    throw new Error('Access to private IP addresses is not allowed');
  }

  if (parsedUrl.username || parsedUrl.password) {
    throw new Error('URLs with credentials are not allowed');
  }

  return parsedUrl;
}

function makeRequest(url, redirectCount = 0) {
  return new Promise((resolve, reject) => {
    if (redirectCount > MAX_REDIRECTS) {
      return reject(new Error('Too many redirects'));
    }

    const parsedUrl = validateURL(url);
    const client = parsedUrl.protocol === 'https:' ? https : http;

    const options = {
      hostname: parsedUrl.hostname,
      port: parsedUrl.port,
      path: parsedUrl.pathname + parsedUrl.search,
      method: 'GET',
      headers: {
        'User-Agent': 'Mozilla/5.0 (compatible; MetadataFetcher/1.0)',
        'Accept': 'text/html,application/xhtml+xml',
        'Accept-Language': 'en-US,en;q=0.9'
      },
      timeout: TIMEOUT,
      lookup: (hostname, options, callback) => {
        require('dns').lookup(hostname, options, (err, address, family) => {
          if (err) {
            return callback(err);
          }
          if (isPrivateIP(address)) {
            return callback(new Error('Resolved IP address is private'));
          }
          callback(null, address, family);
        });
      }
    };

    const req = client.request(options, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        const redirectUrl = new URL(res.headers.location, url).href;
        return makeRequest(redirectUrl, redirectCount + 1)
          .then(resolve)
          .catch(reject);
      }

      if (res.statusCode !== 200) {
        return reject(new Error(`HTTP ${res.statusCode}`));
      }

      let data = '';
      let size = 0;

      res.on('data', (chunk) => {
        size += chunk.length;
        if (size > MAX_RESPONSE_SIZE) {
          req.destroy();
          return reject(new Error('Response too large'));
        }
        data += chunk;
      });

      res.on('end', () => {
        resolve(data);
      });
    });

    req.on('error', (error) => {
      reject(error);
    });

    req.on('timeout', () => {
      req.destroy();
      reject(new Error('Request timeout'));
    });

    req.end();
  });
}

function extractMetadata(html) {
  const metadata = {
    title: null,
    description: null,
    ogTitle: null,
    ogDescription: null,
    ogImage: null,
    ogUrl: null,
    ogType: null,
    ogSiteName: null
  };

  const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  if (titleMatch) {
    metadata.title = titleMatch[1].trim();
  }

  const descriptionMatch = html.match(/<meta\s+name=["']description["']\s+content=["']([^"']+)["']/i);
  if (descriptionMatch) {
    metadata.description = descriptionMatch[1].trim();
  }

  const ogTags = {
    'og:title': 'ogTitle',
    'og:description': 'ogDescription',
    'og:image': 'ogImage',
    'og:url': 'ogUrl',
    'og:type': 'ogType',
    'og:site_name': 'ogSiteName'
  };

  for (const [property, key] of Object.entries(ogTags)) {
    const regex = new RegExp(`<meta\\s+property=["']${property}["']\\s+content=["']([^"']+)["']`, 'i');
    const match = html.match(regex);
    if (match) {
      metadata[key] = match[1].trim();
    }
  }

  return metadata;
}

async function fetchURLMetadata(url) {
  try {
    validateURL(url);
    const html = await makeRequest(url);
    const metadata = extractMetadata(html);
    
    return {
      success: true,
      url: url,
      metadata: metadata
    };
  } catch (error) {
    return {
      success: false,
      url: url,
      error: error.message
    };
  }
}

exports.fetchURLMetadata = fetchURLMetadata;